sql:
SELECT b.battle_name, b.date, b.outcome, cs.colony_state_name
FROM battles AS b
INNER JOIN colonies_states AS cs ON b.colony_state_id = cs.colony_state_id;

SELECT battle_id, total_participants 
FROM battles 
ORDER BY total_participants DESC;

SELECT b.*
FROM battles b
INNER JOIN event_media em ON b.battle_id = em.battle_id;

SELECT AVG(num_battles) AS average_battles_accessed_per_day
FROM (
    SELECT COUNT(DISTINCT battle_id) AS num_battles
    FROM access_logs
    GROUP BY access_date
);

SELECT b.battle_name 
FROM battles b
WHERE b.casualties = (
    SELECT MAX(b2.casualties)
    FROM battles b2
);

SELECT file_type, SUM(file_size) AS total_size
FROM event_media
GROUP BY file_type;

external_knowledge:
(importance is a scale from 1 to 10, where higher values indicate more significant battles; 
a "battle" refers to any military engagement or conflict event; 
sides can be thought of as opposing forces or parties in a conflict, such as countries or factions.)

sql:
SELECT colony_state_name
FROM colonies_states
WHERE population_1770 > 5000;

external_knowledge:
